+export type WindowFrameBoundary = {
+	readonly sql: SQL;
+	readonly order: number;
+};
+
+function boundary(value: string, order: number): WindowFrameBoundary {
+	return { sql: sql.raw(value), order };
+}
+
+export const unboundedPreceding = boundary('unbounded preceding', Number.NEGATIVE_INFINITY);
+export const currentRow = boundary('current row', 0);
+export const unboundedFollowing = boundary('unbounded following', Number.POSITIVE_INFINITY);
+
+function validateFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	validateFrameOffset('preceding', value);
+	return boundary(`${value} preceding`, -value);
+}
+
+export function following(value: number): WindowFrameBoundary {
+	validateFrameOffset('following', value);
+	return boundary(`${value} following`, value);
+}
+
+export type WindowFrame = SQL;
+
+function frame(kind: 'rows' | 'range', { from, to }: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (from.order > to.order) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return sql`${sql.raw(kind)} between ${from.sql} and ${to.sql}`;
+}
+
+export function rows(bounds: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('rows', bounds);
+}
+
+export function range(bounds: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('range', bounds);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export type WindowFunction<T> = SQL<T> & {
+	over(spec?: WindowSpec | string): SQL<T>;
+};
+
+function windowFunction<T>(expression: SQL<T>): WindowFunction<T> {
+	const result = expression as WindowFunction<T>;
+	result.over = (spec: WindowSpec | string = {}): SQL<T> => {
+		if (typeof spec === 'string') {
+			return sql`${expression} over ${sql.identifier(spec)}`;
+		}
+		const partitionBy = spec.partitionBy === undefined
+			? undefined
+			: sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`;
+		const orderBy = spec.orderBy === undefined
+			? undefined
+			: sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`;
+		return sql`${expression} over (${partitionBy}${sql` ${orderBy}`.if(orderBy)}${sql` ${spec.frame}`.if(spec.frame)})`;
+	};
+	return result;
+}
